-- Conversation 1 : Jean (locataire) ↔ Pierre (propriétaire) - Studio Suresnes
INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, created_at)
VALUES ('31000001-0000-0000-0000-000000000001','f94724f9-7a14-4a97-9163-86665fa39d03','317659d8-4251-476a-b05a-f83d8592e107','Question sur le chauffage','Bonjour Pierre, j''ai remarqué que le chauffage collectif prend du temps à monter en température le matin. Est-ce normal ou y a-t-il un réglage à faire ? Merci',true,'2025-02-10 10:30:00','2025-02-10 09:15:00');
INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, parent_id, created_at)
VALUES ('31000001-0000-0000-0000-000000000002','317659d8-4251-476a-b05a-f83d8592e107','f94724f9-7a14-4a97-9163-86665fa39d03','Re: Question sur le chauffage','Bonjour Jean, c''est tout à fait normal pour un chauffage collectif, il peut prendre 20 à 30 min le matin. Si le problème persiste, je contacte le syndic. Bonne journée !',true,'2025-02-10 14:20:00','31000001-0000-0000-0000-000000000001','2025-02-10 10:45:00');
INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, parent_id, created_at)
VALUES ('31000001-0000-0000-0000-000000000003','f94724f9-7a14-4a97-9163-86665fa39d03','317659d8-4251-476a-b05a-f83d8592e107','Re: Question sur le chauffage','OK merci pour la réponse rapide ! Ca va mieux depuis hier effectivement. Bonne journée à vous aussi.',true,'2025-02-11 09:00:00','31000001-0000-0000-0000-000000000002','2025-02-10 15:00:00');

INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, created_at)
VALUES ('31000001-0000-0000-0000-000000000004','317659d8-4251-476a-b05a-f83d8592e107','f94724f9-7a14-4a97-9163-86665fa39d03','Rappel : loyer mai 2026','Bonjour Jean, je vous rappelle que le loyer de mai 2026 (900€) est dû avant le 5 mai. N''hésitez pas si vous avez des questions.',false,NULL,'2026-05-01 08:00:00');
INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, created_at)
VALUES ('31000001-0000-0000-0000-000000000005','f94724f9-7a14-4a97-9163-86665fa39d03','317659d8-4251-476a-b05a-f83d8592e107','Re: Rappel loyer mai 2026','Bonjour, je fais le virement aujourd''hui. Pouvez-vous m''envoyer la quittance dès réception ? Merci',false,NULL,'2026-05-02 11:30:00');

-- Conversation 2 : Sophie ↔ Pierre - T3 Boulogne
INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, created_at)
VALUES ('32000001-0000-0000-0000-000000000001','a6470d69-0b9d-4c63-bdfe-118029895c59','317659d8-4251-476a-b05a-f83d8592e107','Fuite sous évier','Bonjour, j''ai une fuite sous l''évier de la cuisine depuis ce matin. L''eau goutte lentement mais régulièrement. Pouvez-vous envoyer quelqu''un rapidement ? Merci',true,'2025-04-15 09:30:00','2025-04-14 19:45:00');
INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, parent_id, created_at)
VALUES ('32000001-0000-0000-0000-000000000002','317659d8-4251-476a-b05a-f83d8592e107','a6470d69-0b9d-4c63-bdfe-118029895c59','Re: Fuite sous évier','Bonjour Sophie, je contacte le plombier ce matin. Il devrait passer demain entre 14h et 17h, est-ce que ça vous convient ?',true,'2025-04-15 11:00:00','32000001-0000-0000-0000-000000000001','2025-04-15 09:45:00');
INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, parent_id, created_at)
VALUES ('32000001-0000-0000-0000-000000000003','a6470d69-0b9d-4c63-bdfe-118029895c59','317659d8-4251-476a-b05a-f83d8592e107','Re: Fuite sous évier','Oui parfait ! Je serai là. Merci de votre réactivité.',true,'2025-04-15 12:30:00','32000001-0000-0000-0000-000000000002','2025-04-15 11:15:00');
INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, parent_id, created_at)
VALUES ('32000001-0000-0000-0000-000000000004','a6470d69-0b9d-4c63-bdfe-118029895c59','317659d8-4251-476a-b05a-f83d8592e107','Re: Fuite sous évier','Le plombier est passé, la fuite est réparée. C''était un joint usé. Tout est bon maintenant, merci !',true,'2025-04-17 09:00:00','32000001-0000-0000-0000-000000000003','2025-04-16 17:30:00');

-- Conversation 3 : Lucas ↔ Marie - T2 Paris 15e
INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, created_at)
VALUES ('33000001-0000-0000-0000-000000000001','e3b13c7e-3a2f-40f6-b18f-edaf9ff4f9f0','75940717-a4d7-4644-a9fc-ab2de65a0660','Voisinage bruyant','Bonjour Marie, je souhaitais vous signaler que les voisins du dessus font beaucoup de bruit le soir (après 22h). Y a-t-il un recours via le syndic ? Merci',true,'2025-03-20 10:00:00','2025-03-19 22:30:00');
