VALUES ('33000001-0000-0000-0000-000000000002','75940717-a4d7-4644-a9fc-ab2de65a0660','e3b13c7e-3a2f-40f6-b18f-edaf9ff4f9f0','Re: Voisinage bruyant','Bonjour Lucas, je comprends. Je vais envoyer un courrier au syndic et contacter directement le locataire du dessus. Je vous tiens informé.',true,'2025-03-21 08:00:00','33000001-0000-0000-0000-000000000001','2025-03-20 10:30:00');
INSERT INTO messages (id, sender_id, recipient_id, subject, body, is_read, read_at, parent_id, created_at)
VALUES ('33000001-0000-0000-0000-000000000003','e3b13c7e-3a2f-40f6-b18f-edaf9ff4f9f0','75940717-a4d7-4644-a9fc-ab2de65a0660','Re: Voisinage bruyant','Merci beaucoup. Depuis votre intervention c''est beaucoup plus calme, je vous en suis reconnaissant.',true,'2025-03-25 09:00:00','33000001-0000-0000-0000-000000000002','2025-03-24 20:00:00');

